import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = 1
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = -1

    def display(self):
        print("   a b c d e f g h")
        for i in range(8):
            print(f"{i+1} ", end="")
            for j in range(8):
                if self.board[i, j] == 0:
                    print(". ", end="")
                elif self.board[i, j] == 1:
                    print("O ", end="")
                else:
                    print("X ", end="")
            print()
```

